/**
 * Phase 34: Canadian vendor library seed for Smart Match Layer 1.
 *
 * 1,500 entries covering top vendors across grocery, fuel, restaurants,
 * SaaS, telecom, banks, retail, transportation, lodging, government,
 * healthcare, and professional services. Patterns are normalized lowercase
 * substrings; the matcher applies the same normalization to transaction
 * descriptions before testing.
 *
 * SOURCE OF TRUTH: this file. Re-running POST /admin/seed-vendor-library
 * upserts by vendor_pattern (existing rows update; new rows insert).
 *
 * EDITING GUIDE:
 *   pattern         lowercase substring/regex matched against tx description
 *   display         canonical merchant name shown in UI chips
 *   category_hint   one of: meals, fuel, software, office_supplies,
 *                   utilities, subscription, travel, lodging, groceries,
 *                   retail, telecom, banking, healthcare, government,
 *                   professional, transportation, entertainment, fitness
 *   account_subtype CoA subtype hint; null = use category_hint default
 *   default_personal true if vendor is typically personal spending
 *   confidence      'high' | 'medium' | 'low'; default 'medium'
 *   priority        lower = matched first; default 100; demote ambiguous
 *                   patterns (e.g. amazon could be retail/groceries/AWS)
 */

export interface VendorLibraryEntry {
  pattern: string;
  display: string;
  category_hint: string;
  account_subtype: string | null;
  default_personal: boolean;
  confidence: 'high' | 'medium' | 'low';
  priority: number;
}

